/**
 * CategoryConfiguration entity with Zod validation
 *
 * Enhanced configuration management supporting the sophisticated 9-stage
 * classification pipeline with validation per SCORING_LOGIC.md tuning parameters.
 */

import { z } from 'zod';

/**
 * Main category configuration interface matching the sophisticated
 * processingConfig structure from email-categorizer-config.json
 */
export interface CategoryConfiguration {
  version: string; // Semantic version
  lastModified: Date;
  hash: string; // Content hash for validation

  // Main processing configuration
  processingConfig: ProcessingConfig;

  // Validation metadata
  schemaVersion: string;
  validationPassed: boolean;
  validationErrors: string[];

  // Runtime optimization
  compiledRules: CompiledRule[]; // Pre-compiled for performance
  attributeMatrix: AttributeInfluenceMatrix; // Pre-computed influence matrix
}

/**
 * Processing configuration matching the structure from SCORING_LOGIC.md
 */
export interface ProcessingConfig {
  version: number;
  taxonomyNotes: string;
  settings: ProcessingSettings;
  categorySignals: Record<string, CategorySignals>;
  confidenceThresholds: ConfidenceThresholds;
  multiLabelPolicy: MultiLabelPolicy;
  domainSignalOverrides: DomainOverrides;
  domainSignalResolution: DomainResolution;
  topLevelCategories: Record<string, TopLevelCategory>;
  attributes: AttributeSystem;
  attributeRelevance: AttributeRelevanceMatrix;
  aiPrompts: AIPromptSystem;
  featureExtractionSchema: JSONSchema;
}

/**
 * Processing settings implementing all tuning parameters from SCORING_LOGIC.md
 */
export interface ProcessingSettings {
  initialization: {
    applyHardAssertions: boolean;
    seedCategoryScores: boolean;
  };
  ruleScoring: {
    useLexicalPatterns: boolean;
    applySubtypeRules: boolean;
    boundedAggregation: boolean;
  };
  attributeProcessing: {
    detectSelfSent: boolean;
    resolveDomains: boolean;
    deriveContextFlags: boolean;
  };
  attributeInfluence: {
    applyBonuses: boolean;
    applyPenalties: boolean;
    enforceCaps: boolean;
  };
  disambiguation?: {
    pairwiseAdjustments: boolean;
    confidenceGapThreshold: number;
    maxAdjustmentsPerEmail?: number;
    adjustmentDecayFactor?: number;
    enableSubtypeDisambiguation?: boolean;
  };
  multiLabelSelection: {
    maxLabels: number;
    minSecondaryConfidence: number;
    allowedCombinations: string[];
  };
  aiRouting: {
    highConfidenceThreshold: number;
    aiRequiredThreshold: number;
    skipAiConditions: string[];
  };
}

/**
 * Category signals for hard assertions and strong indicators
 */
export interface CategorySignals {
  hardAssertions: {
    fromDomainsRef?: {
      sourceGroup: string;
      confidence: string;
    };
    subjectPrefixes?: string[];
    fromAddresses?: string[];
  };
  strongIndicators: {
    fromDomainsRef?: {
      sourceGroup: string;
      confidence: string;
    };
    subjectContains?: string[];
    bodyContains?: string[];
  };
  disambiguators?: {
    boostIfPresentAttributes?: string[];
    suppressIfBodyContains?: string[];
    boostIfAbsentCategories?: string[];
  };
}

/**
 * Confidence thresholds for classification decisions
 */
export interface ConfidenceThresholds {
  highConfidence: number;
  mediumConfidence: number;
  lowConfidence: number;
  aiClassificationRequired: number;
  manualReviewRequired: number;
  secondaryLabelMinGap: number;
}

/**
 * Multi-label policy configuration
 */
export interface MultiLabelPolicy {
  maxTopLevelLabels: number;
  minConfidenceForAdditional: number;
  minDeltaPrimarySecondary: number;
  allowFinancialActionableCopresence: boolean;
}

/**
 * Domain signal overrides for specific category behaviors
 */
export interface DomainOverrides {
  [category: string]: {
    hardInclude: string[];
    hardExclude: string[];
    strongInclude: string[];
    strongExclude: string[];
  };
}

/**
 * Domain resolution configuration
 */
export interface DomainResolution {
  mode: string; // "runtimeResolved"
  source: string; // "config/domain-sources.json"
  notes: string;
}

/**
 * Top-level category definition with subtypes and AI classification
 */
export interface TopLevelCategory {
  description: string;
  subtypes: Record<string, SubtypeDefinition>;
  aiFinalClassification: {
    categoryDescription: string;
    decisionCriteria: string[];
    exclusionCriteria?: string[];
  };
}

/**
 * Subtype definition with rule-based classification
 */
export interface SubtypeDefinition {
  description: string;
  ruleBasedClassification?: {
    highConfidence?: RulePattern[];
    mediumConfidence?: RulePattern[];
    lowConfidence?: RulePattern[];
  };
  derived?: boolean;
  derivationLogic?: string;
}

/**
 * Rule pattern for rule-based classification
 */
export interface RulePattern {
  field: string; // "subject", "body", "from.address", etc.
  operation: string; // "containsAny", "startsWith", "endsWith", "regexAny", "exists"
  values?: string[];
  weight: number;
}

/**
 * Attribute system configuration
 */
export interface AttributeSystem {
  schema: Record<string, AttributeSchema>;
  detectors: AttributeDetector[];
  derived: Record<string, DerivedAttribute>;
  attributeBonusMap: Record<string, Record<string, number>>;
}

export interface AttributeSchema {
  type: string; // "enum", "boolean"
  values?: string[]; // For enum types
  description: string;
}

export interface AttributeDetector {
  attribute: string;
  field: string;
  operation: string;
  values: string[];
}

export interface DerivedAttribute {
  logic: string;
  notes: string;
}

/**
 * Attribute relevance matrix implementing roles from SCORING_LOGIC.md
 */
export interface AttributeRelevanceMatrix {
  RolesLegend: {
    CORE: string;
    PRIMARY_BOOST: string;
    SECONDARY_BOOST: string;
    DISAMBIGUATOR: string;
    FILTER: string;
    STRUCTURAL: string;
    DERIVED_LINK: string;
    NEUTRAL: string;
  };
  [category: string]:
    | {
        categoryRoles: Record<string, AttributeRole>;
        subtypes?: Record<
          string,
          {
            roles: Record<string, AttributeRole>;
          }
        >;
      }
    | {
        CORE: string;
        PRIMARY_BOOST: string;
        SECONDARY_BOOST: string;
        DISAMBIGUATOR: string;
        FILTER: string;
        STRUCTURAL: string;
        DERIVED_LINK: string;
        NEUTRAL: string;
      }; // For _roles_legend
}

export type AttributeRole =
  | 'CORE'
  | 'PRIMARY_BOOST'
  | 'SECONDARY_BOOST'
  | 'DISAMBIGUATOR'
  | 'FILTER'
  | 'STRUCTURAL'
  | 'DERIVED_LINK'
  | 'NEUTRAL';

/**
 * AI prompt system configuration
 */
export interface AIPromptSystem {
  featureExtraction: {
    systemPrompt: string[];
    userPrompt: string[];
  };
  finalClassification: {
    systemPrompt: string[];
    userPrompt: string[];
  };
}

/**
 * JSON schema for feature extraction
 */
export interface JSONSchema {
  type: string;
  properties: Record<string, JSONSchemaProperty>;
  required: string[];
  additionalProperties: boolean;
}

export interface JSONSchemaProperty {
  type: string;
  description?: string;
  enum?: string[];
  items?: JSONSchemaProperty;
  properties?: Record<string, JSONSchemaProperty>;
  required?: string[];
}

/**
 * Pre-compiled rule for performance optimization
 */
export interface CompiledRule {
  category: string;
  subtype: string;
  tier: string;
  pattern: RegExp;
  weight: number;
}

/**
 * Pre-computed attribute influence matrix for performance
 */
export interface AttributeInfluenceMatrix {
  [category: string]: {
    [attribute: string]: {
      role: AttributeRole;
      bonus: number;
      cap: number;
    };
  };
}

/**
 * Zod schema for runtime validation of CategoryConfiguration
 * This implements all tuning parameters from SCORING_LOGIC.md
 */
export const CategoryConfigurationSchema = z.object({
  version: z.string(),
  lastModified: z.date(),
  hash: z.string(),

  processingConfig: z.object({
    version: z.number(),
    taxonomyNotes: z.string(),

    settings: z.object({
      initialization: z.object({
        applyHardAssertions: z.boolean(),
        seedCategoryScores: z.boolean(),
      }),
      ruleScoring: z.object({
        useLexicalPatterns: z.boolean(),
        applySubtypeRules: z.boolean(),
        boundedAggregation: z.boolean(),
      }),
      attributeProcessing: z.object({
        detectSelfSent: z.boolean(),
        resolveDomains: z.boolean(),
        deriveContextFlags: z.boolean(),
      }),
      attributeInfluence: z.object({
        applyBonuses: z.boolean(),
        applyPenalties: z.boolean(),
        enforceCaps: z.boolean(),
      }),
      disambiguation: z.object({
        pairwiseAdjustments: z.boolean(),
        confidenceGapThreshold: z.number().min(0).max(1),
      }),
      multiLabelSelection: z.object({
        maxLabels: z.number().int().positive(),
        minSecondaryConfidence: z.number().min(0).max(1),
        allowedCombinations: z.array(z.string()),
      }),
      aiRouting: z.object({
        highConfidenceThreshold: z.number().min(0).max(1),
        aiRequiredThreshold: z.number().min(0).max(1),
        skipAiConditions: z.array(z.string()),
      }),
    }),

    categorySignals: z.record(
      z.object({
        hardAssertions: z.object({
          fromDomainsRef: z
            .object({
              sourceGroup: z.string(),
              confidence: z.string(),
            })
            .optional(),
          subjectPrefixes: z.array(z.string()).optional(),
          fromAddresses: z.array(z.string()).optional(),
        }),
        strongIndicators: z.object({
          fromDomainsRef: z
            .object({
              sourceGroup: z.string(),
              confidence: z.string(),
            })
            .optional(),
          subjectContains: z.array(z.string()).optional(),
          bodyContains: z.array(z.string()).optional(),
        }),
        disambiguators: z
          .object({
            boostIfPresentAttributes: z.array(z.string()).optional(),
            suppressIfBodyContains: z.array(z.string()).optional(),
            boostIfAbsentCategories: z.array(z.string()).optional(),
          })
          .optional(),
      })
    ),

    confidenceThresholds: z.object({
      highConfidence: z.number().min(0).max(1),
      mediumConfidence: z.number().min(0).max(1),
      lowConfidence: z.number().min(0).max(1),
      aiClassificationRequired: z.number().min(0).max(1),
      manualReviewRequired: z.number().min(0).max(1),
      secondaryLabelMinGap: z.number().min(0).max(1),
    }),

    multiLabelPolicy: z.object({
      maxTopLevelLabels: z.number().int().positive(),
      minConfidenceForAdditional: z.number().min(0).max(1),
      minDeltaPrimarySecondary: z.number().min(0).max(1),
      allowFinancialActionableCopresence: z.boolean(),
    }),

    // Additional configuration sections...
    domainSignalOverrides: z.record(
      z.object({
        hardInclude: z.array(z.string()),
        hardExclude: z.array(z.string()),
        strongInclude: z.array(z.string()),
        strongExclude: z.array(z.string()),
      })
    ),

    domainSignalResolution: z.object({
      mode: z.string(),
      source: z.string(),
      notes: z.string(),
    }),

    topLevelCategories: z.record(
      z.object({
        description: z.string(),
        subtypes: z.record(
          z.object({
            description: z.string(),
            ruleBasedClassification: z
              .object({
                highConfidence: z
                  .array(
                    z.object({
                      field: z.string(),
                      operation: z.string(),
                      values: z.array(z.string()).optional(),
                      weight: z.number(),
                    })
                  )
                  .optional(),
                mediumConfidence: z
                  .array(
                    z.object({
                      field: z.string(),
                      operation: z.string(),
                      values: z.array(z.string()).optional(),
                      weight: z.number(),
                    })
                  )
                  .optional(),
                lowConfidence: z
                  .array(
                    z.object({
                      field: z.string(),
                      operation: z.string(),
                      values: z.array(z.string()).optional(),
                      weight: z.number(),
                    })
                  )
                  .optional(),
              })
              .optional(),
            derived: z.boolean().optional(),
            derivationLogic: z.string().optional(),
          })
        ),
        aiFinalClassification: z.object({
          categoryDescription: z.string(),
          decisionCriteria: z.array(z.string()),
          exclusionCriteria: z.array(z.string()).optional(),
        }),
      })
    ),

    attributes: z.object({
      schema: z.record(
        z.object({
          type: z.string(),
          values: z.array(z.string()).optional(),
          description: z.string(),
        })
      ),
      detectors: z.array(
        z.object({
          attribute: z.string(),
          field: z.string(),
          operation: z.string(),
          values: z.array(z.string()),
        })
      ),
      derived: z.record(
        z.object({
          logic: z.string(),
          notes: z.string(),
        })
      ),
      attributeBonusMap: z.record(z.record(z.number())),
    }),

    attributeRelevance: z.record(z.any()), // Complex nested structure, validated separately

    aiPrompts: z.object({
      featureExtraction: z.object({
        systemPrompt: z.array(z.string()),
        userPrompt: z.array(z.string()),
      }),
      finalClassification: z.object({
        systemPrompt: z.array(z.string()),
        userPrompt: z.array(z.string()),
      }),
    }),

    featureExtractionSchema: z.object({
      type: z.string(),
      properties: z.record(z.any()),
      required: z.array(z.string()),
    }),
  }),

  schemaVersion: z.string(),
  validationPassed: z.boolean(),
  validationErrors: z.array(z.string()),
  compiledRules: z.array(z.any()), // Compiled at runtime
  attributeMatrix: z.record(z.any()), // Pre-computed at runtime
});

export type ValidatedCategoryConfiguration = z.infer<typeof CategoryConfigurationSchema>;

